input.command:
powershell -Command "
# Download Supabase CLI Windows binary
\$url = 'https://github.com/supabase/cli/releases/download/v1.234.0/supabase_windows_amd64.exe'
\$output = 'C:\Users\User\AppData\Local\Programs\supabase.exe'

New-Item -ItemType Directory -Path 'C:\Users\User\AppData\Local\Programs' -Force -ErrorAction SilentlyContinue | Out-Null

Write-Host 'Baixando Supabase CLI...'
try {
  Invoke-WebRequest -Uri \$url -OutFile \$output -ErrorAction Stop
  Write-Host '✅ Supabase baixado com sucesso'

  # Add to PATH
  \$pathVar = [Environment]::GetEnvironmentVariable('Path', 'User')
  if (-not \$pathVar.Contains('C:\Users\User\AppData\Local\Programs')) {
    [Environment]::SetEnvironmentVariable('Path', \"\$pathVar;C:\Users\User\AppData\Local\Programs\", 'User')
    Write-Host '✅ Supabase adicionado ao PATH'
  }
} catch {
  Write-Host '❌ Erro ao baixar: \$(\$_.Exception.Message)'
}
" 2>&1

powershell -Command "
# Usar Chrome/Edge para gerar PDF via CLI
\$htmlPath = 'C:\Users\User\code5\docs\AIOS-Setup-Guide.html'
\$pdfPath = 'C:\Users\User\code5\docs\AIOS-Setup-Guide.pdf'

# Tentar com Edge (mais comum no Windows 11)
\$edgePath = 'C:\Program Files (x86)\Microsoft\Edge\Application\msedge.exe'
if (Test-Path \$edgePath) {
  & \$edgePath --headless --disable-gpu --print-to-pdf=\$pdfPath \$htmlPath 2>&1
  Start-Sleep -Seconds 3

  if (Test-Path \$pdfPath) {
    Write-Host '✅ PDF criado com sucesso!'
    Get-Item \$pdfPath | Select-Object Length, LastWriteTime
  } else {
    Write-Host '⚠️ PDF não foi gerado'
  }
} else {
  Write-Host '⚠️ Microsoft Edge não encontrado'
  Write-Host 'Abra o HTML no navegador e use Imprimir → Salvar como PDF'
}
" 2>&1
